package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.Test;
import org.junit.jupiter.api.BeforeEach;
import org.mockito.Mockito;
import java.util.Arrays;

public class CSVFormatTest {

    private CSVFormat csvFormat1;
    private CSVFormat csvFormat2;

    @BeforeEach
    public void setup() {
        csvFormat1 = new CSVFormat(',', '"', null, null, null, false, true, "\r\n", null, null, false, false);
        csvFormat2 = new CSVFormat(',', '"', null, null, null, false, true, "\r\n", null, null, false, false);
    }

    @Test
    public void testEquals_SameInstance() {
        assertTrue(csvFormat1.equals(csvFormat1));
    }

    @Test
    public void testEquals_NullObject() {
        assertFalse(csvFormat1.equals(null));
    }

    @Test
    public void testEquals_DifferentClass() {
        assertFalse(csvFormat1.equals("Not a CSVFormat object"));
    }

    @Test
    public void testEquals_EqualObjects() {
        assertTrue(csvFormat1.equals(csvFormat2));
    }

    @Test
    public void testEquals_DifferentDelimiter() {
        CSVFormat csvFormatDiffDelimiter = new CSVFormat('|', '"', null, null, null, false, true, "\r\n", null, null, false, false);
        assertFalse(csvFormat1.equals(csvFormatDiffDelimiter));
    }

    // Add more test cases for other fields comparison

}
